## 📝 **IMPLEMENTATION CODE**

### **1. BACKEND: `fan_layout.py`** (Phase 14 Core)

```python
# /backend/fan_layout.py
from datetime import datetime
from typing import List, Dict, Any
import math

class FileLayoutCalculator:
    """Calculates time-sorted Y positions for files"""

    FILE_SPACING_BASE = 35  # pixels between files
    FILE_SPACING_GROWTH = 2.0  # adaptive spacing factor

    def __init__(self, parent_y: float, files: List[Dict[str, Any]]):
        self.parent_y = parent_y
        self.files = self._sort_by_time(files)
        self.file_count = len(self.files)

    def _sort_by_time(self, files: List[Dict[str, Any]]) -> List[Dict[str, Any]]:
        """Sort files by created_time (oldest first)"""
        return sorted(
            files,
            key=lambda f: f.get('created_time', datetime.min)
        )

    def _calculate_spacing(self) -> float:
        """Adaptive spacing based on file count"""
        if self.file_count <= 5:
            return self.FILE_SPACING_BASE
        return self.FILE_SPACING_BASE + (self.file_count * self.FILE_SPACING_GROWTH)

    def get_positions(self) -> Dict[int, Dict[str, float]]:
        """
        Returns: {file_id: {'x': x, 'y': y}}
        """
        positions = {}
        spacing = self._calculate_spacing()

        # Calculate median index for vertical stacking
        mid_index = (self.file_count - 1) / 2

        for i, file in enumerate(self.files):
            # Vertical stacking: older files at bottom (lower Y)
            # i=0 (oldest) gets lowest Y, i=n (newest) gets highest Y
            y_offset = (i - mid_index) * spacing
            file_y = self.parent_y + y_offset

            positions[file['id']] = {
                'x': 0,  # Will be adjusted by parent's X + offset
                'y': file_y,
                'z': 0
            }

        return positions

# Usage in backend route
def calculate_file_positions(parent_y: float, files: List[Dict]) -> Dict:
    """Entry point for Phase 14 calculations"""
    calculator = FileLayoutCalculator(parent_y, files)
    return calculator.get_positions()
```

