### **2. API: `tree_routes.py`** (Serialization Layer)

```python
# /backend/api/tree_routes.py
from fastapi import APIRouter, HTTPException
from fan_layout import calculate_file_positions
from typing import Dict, Any, List

router = APIRouter()

@router.get("/tree/{folder_id}")
async def get_tree_structure(folder_id: str):
    """
    Returns tree with visual_hints.layout_hint for each file
    """
    # Fetch folder and its children from DB
    folder = await db.get_folder(folder_id)
    files = await db.get_files_in_folder(folder_id)

    # Phase 14: Calculate backend positions
    file_positions = calculate_file_positions(
        parent_y=folder['y_position'],
        files=files
    )

    # Enrich files with layout hints
    enriched_files = []
    for file in files:
        file_id = file['id']
        if file_id in file_positions:
            pos = file_positions[file_id]
            file['visual_hints'] = {
                'layout_hint': {
                    'expected_x': pos['x'],
                    'expected_y': pos['y'],
                    'expected_z': pos['z']
                }
            }
        enriched_files.append(file)

    return {
        'folder': folder,
        'files': enriched_files,
        'metadata': {
            'backend_positions': True,
            'file_count': len(files),
            'spacing': FileLayoutCalculator.FILE_SPACING_BASE
        }
    }
```

