### **3. FRONTEND: `tree_renderer.py`** (The Fix!)

```javascript
// /frontend/src/visualizer/tree_renderer.js
// Lines 2929-2939 (as mentioned in report)

// Constants
const FILE_GOLDEN_ANGLE = 137.5 * (Math.PI / 180); // Only for fallback
const FILE_RADIUS_BASE = 40;
const FILE_RADIUS_GROWTH = 5;
const FILE_SPACING = 35; // Should match backend

/**
 * Calculate file position with PRIORITY ORDER:
 * 1. Sugiyama positions
 * 2. Backend layout_hint
 * 3. Local calculation (fallback)
 */
function calculateFilePosition(file, localIdx, siblings, parentPos, sugiyamaPositions) {
    let x, y, z;
    const globalIdx = file.globalIndex || localIdx;

    // PRIORITY 1: Sugiyama mode (rare)
    if (sugiyamaPositions && sugiyamaPositions[file.id]) {
        const sp = sugiyamaPositions[file.id];
        x = sp.x + treeOffset;
        y = sp.y;
        z = 0;
        console.log(`[FILE] ${file.name} using SUGIYAMA Y=${y.toFixed(0)}`);

    // PRIORITY 2: ✅ BACKEND POSITIONS (Phase 17.9 FIX!)
    } else if (file.visual_hints?.layout_hint) {
        const hint = file.visual_hints.layout_hint;

        // Use backend-calculated Y (time-sorted)
        x = (hint.expected_x || parentPos.x) + treeOffset;
        y = hint.expected_y ?? (parentPos.y + 40);
        z = hint.expected_z || 0;

        // Debug logging
        if (globalIdx < 5) {
            console.log(`[FILE] ${file.name} using BACKEND Y=${y.toFixed(0)}`);
        }

    // PRIORITY 3: Local calculation (fallback only)
    } else {
        console.warn(`[FILE] ${file.name} using LOCAL Y (no backend data)`);

        // Original fallback logic (only for orphan files)
        const theta = localIdx * FILE_GOLDEN_ANGLE;
        const radius = FILE_RADIUS_BASE + Math.sqrt(localIdx + 1) * FILE_RADIUS_GROWTH;
        x = parentPos.x + Math.cos(theta) * radius;
        z = 0;
        y = calculateFileY(file, localIdx, siblings, parentPos.y);
    }

    return { x, y, z };
}

// Helper function for fallback
function calculateFileY(file, localIdx, siblings, parentY) {
    // Legacy fallback for orphan files
    const spacing = FILE_SPACING;
    const midIndex = (siblings.length - 1) / 2;
    return parentY + (localIdx - midIndex) * spacing;
}
```

