// /frontend/src/visualizer/file_mesh.js

function createFileMesh(fileData, position, color = 0x4CAF50) {
    // Create geometry
    const geometry = new THREE.BoxGeometry(20, 20, 20);
    const material = new THREE.MeshStandardMaterial({ 
        color: color,
        metalness: 0.3,
        roughness: 0.7 
    });

    const mesh = new THREE.Mesh(geometry, material);

    // ✅ CRITICAL: Use backend-calculated position
    mesh.position.set(position.x, position.y, position.z);

    // Store metadata
    mesh.userData = {
        fileId: fileData.id,
        name: fileData.name,
        createdTime: fileData.created_time,
        backendY: position.y, // For debugging
        source: position.source || 'backend'
    };

    return mesh;
}

// Usage in rendering loop
function renderFiles(files, parentPos, sugiyamaPositions) {
    const fileMeshes = [];

    files.forEach((file, index) => {
        const pos = calculateFilePosition(
            file,
            index,
            files,
            parentPos,
            sugiyamaPositions
        );

        const mesh = createFileMesh(file, pos);
        fileMeshes.push(mesh);
        scene.add(mesh);
    });

    return fileMeshes;
}

