"""
Phase 80.10: Provider Registry Architecture
===========================================
Clean separation: Orchestrator selects provider. call_model only executes.

Based on ChatGPT architectural recommendation:
- ProviderRegistry: singleton registry for all providers
- BaseProvider: abstract interface with supports_tools flag
- Provider implementations: OpenAI, Anthropic, Google, Ollama, OpenRouter
"""

import os
import asyncio
import time
import json
from abc import ABC, abstractmethod
from typing import Dict, List, Optional, Any, AsyncGenerator
from enum import Enum
from dataclasses import dataclass

import logging
logger = logging.getLogger(__name__)


# Phase 80.39: Custom exception for xai key exhaustion
class XaiKeysExhausted(Exception):
    """Raised when all xai keys return 403 - signals to use OpenRouter fallback"""
    pass


class Provider(Enum):
    """Supported providers"""
    OPENAI = "openai"
    ANTHROPIC = "anthropic"
    GOOGLE = "google"  # Note: config.json uses "gemini" key, APIKeyService maps google->gemini
    GEMINI = "gemini"  # Phase 80.41: Added for config.json compatibility
    OLLAMA = "ollama"
    OPENROUTER = "openrouter"
    XAI = "xai"  # Phase 80.35: x.ai (Grok models)


@dataclass
class ProviderConfig:
    """Configuration for a provider"""
    api_key: Optional[str] = None
    base_url: Optional[str] = None
    default_model: Optional[str] = None


class BaseProvider(ABC):
    """
    Abstract base class for all LLM providers.
    Each provider implements its own call() method with native tool support.
    """

    def __init__(self, config: ProviderConfig):
        self.config = config

    @property
    @abstractmethod
    def supports_tools(self) -> bool:
        """Whether this provider supports native function calling"""
        pass

    @property
    @abstractmethod
    def name(self) -> str:
        """Provider name for logging"""
        pass

    @abstractmethod
    async def call(
        self,
        messages: List[Dict[str, str]],
        model: str,
        tools: Optional[List[Dict]] = None,
        **kwargs
    ) -> Dict[str, Any]:
        """
        Call the LLM with given messages.

        Returns standardized response:
        {
            "message": {"content": str, "tool_calls": Optional[List]},
            "model": str,
            "provider": str,
            "usage": Optional[Dict]
        }
        """
        pass


class OpenAIProvider(BaseProvider):
    """OpenAI API provider (GPT models)"""

    @property
    def supports_tools(self) -> bool:
        return True

    @property
    def name(self) -> str:
        return "OpenAI"

    async def call(
        self,
        messages: List[Dict[str, str]],
        model: str,
        tools: Optional[List[Dict]] = None,
        **kwargs
    ) -> Dict[str, Any]:
        start_time = time.time()

        # Get API key
        api_key = self.config.api_key
        if not api_key:
            from src.orchestration.services.api_key_service import APIKeyService
            api_key = APIKeyService().get_key('openai')

        if not api_key:
            raise ValueError("OpenAI API key not found")

        # Clean model name (remove openai/ prefix if present)
        clean_model = model.replace('openai/', '')

        print(f"[OPENAI] Calling {clean_model} (tools: {len(tools) if tools else 0})")

        import httpx

        headers = {
            "Authorization": f"Bearer {api_key}",
            "Content-Type": "application/json"
        }

        payload = {
            "model": clean_model,
            "messages": messages,
            "temperature": kwargs.get("temperature", 0.7),
        }

        if tools:
            # Convert to OpenAI tool format
            payload["tools"] = [
                {"type": "function", "function": t} if "type" not in t else t
                for t in tools
            ]

        async with httpx.AsyncClient(timeout=120.0) as client:
            response = await client.post(
                "https://api.openai.com/v1/chat/completions",
                headers=headers,
                json=payload
            )
            response.raise_for_status()
            data = response.json()

        duration = time.time() - start_time
        print(f"[OPENAI] ✅ Completed in {duration:.1f}s")

        choice = data.get("choices", [{}])[0]
        message = choice.get("message", {})

        return {
            "message": {
                "content": message.get("content", ""),
                "tool_calls": message.get("tool_calls"),
                "role": message.get("role", "assistant")
            },
            "model": clean_model,
            "provider": "openai",
            "usage": data.get("usage")
        }


class AnthropicProvider(BaseProvider):
    """Anthropic API provider (Claude models)"""

    @property
    def supports_tools(self) -> bool:
        return True

    @property
    def name(self) -> str:
        return "Anthropic"

    async def call(
        self,
        messages: List[Dict[str, str]],
        model: str,
        tools: Optional[List[Dict]] = None,
        **kwargs
    ) -> Dict[str, Any]:
        start_time = time.time()

        api_key = self.config.api_key
        if not api_key:
            from src.orchestration.services.api_key_service import APIKeyService
            api_key = APIKeyService().get_key('anthropic')

        if not api_key:
            raise ValueError("Anthropic API key not found")

        # Clean model name
        clean_model = model.replace('anthropic/', '')

        print(f"[ANTHROPIC] Calling {clean_model} (tools: {len(tools) if tools else 0})")

        import httpx

        headers = {
            "x-api-key": api_key,
            "Content-Type": "application/json",
            "anthropic-version": "2023-06-01"
        }

        # Convert messages format (Anthropic uses different format)
        system_content = ""
        anthropic_messages = []
        for msg in messages:
            if msg["role"] == "system":
                system_content = msg["content"]
            else:
                anthropic_messages.append({
                    "role": msg["role"],
                    "content": msg["content"]
                })

        payload = {
            "model": clean_model,
            "max_tokens": kwargs.get("max_tokens", 4096),
            "messages": anthropic_messages,
        }

        if system_content:
            payload["system"] = system_content

        if tools:
            # Convert to Anthropic tool format
            payload["tools"] = [
                {
                    "name": t.get("name"),
                    "description": t.get("description", ""),
                    "input_schema": t.get("parameters", t.get("input_schema", {}))
                }
                for t in tools
            ]

        async with httpx.AsyncClient(timeout=120.0) as client:
            response = await client.post(
                "https://api.anthropic.com/v1/messages",
                headers=headers,
                json=payload
            )
            response.raise_for_status()
            data = response.json()

        duration = time.time() - start_time
        print(f"[ANTHROPIC] ✅ Completed in {duration:.1f}s")

        # Extract content from Anthropic response
        content_blocks = data.get("content", [])
        text_content = ""
        tool_calls = []

        for block in content_blocks:
            if block.get("type") == "text":
                text_content += block.get("text", "")
            elif block.get("type") == "tool_use":
                tool_calls.append({
                    "id": block.get("id"),
                    "type": "function",
                    "function": {
                        "name": block.get("name"),
                        "arguments": json.dumps(block.get("input", {}))
                    }
                })

        return {
            "message": {
                "content": text_content,
                "tool_calls": tool_calls if tool_calls else None,
                "role": "assistant"
            },
            "model": clean_model,
            "provider": "anthropic",
            "usage": data.get("usage")
        }


class GoogleProvider(BaseProvider):
    """Google Gemini API provider"""

    @property
    def supports_tools(self) -> bool:
        return True

    @property
    def name(self) -> str:
        return "Google"

    async def call(
        self,
        messages: List[Dict[str, str]],
        model: str,
        tools: Optional[List[Dict]] = None,
        **kwargs
    ) -> Dict[str, Any]:
        start_time = time.time()

        api_key = self.config.api_key
        if not api_key:
            from src.orchestration.services.api_key_service import APIKeyService
            # Phase 80.42: Use 'gemini' to match config.json key storage
            api_key = APIKeyService().get_key('gemini')

        if not api_key:
            raise ValueError("Google API key not found")

        # Clean model name
        clean_model = model.replace('google/', '')

        print(f"[GOOGLE] Calling {clean_model} (tools: {len(tools) if tools else 0})")

        import httpx

        # Convert messages to Gemini format
        gemini_contents = []
        system_instruction = None

        for msg in messages:
            if msg["role"] == "system":
                system_instruction = msg["content"]
            else:
                role = "user" if msg["role"] == "user" else "model"
                gemini_contents.append({
                    "role": role,
                    "parts": [{"text": msg["content"]}]
                })

        payload = {
            "contents": gemini_contents,
            "generationConfig": {
                "temperature": kwargs.get("temperature", 0.7),
                "maxOutputTokens": kwargs.get("max_tokens", 4096)
            }
        }

        if system_instruction:
            payload["systemInstruction"] = {"parts": [{"text": system_instruction}]}

        if tools:
            # Convert to Gemini tool format
            function_declarations = []
            for t in tools:
                function_declarations.append({
                    "name": t.get("name"),
                    "description": t.get("description", ""),
                    "parameters": t.get("parameters", {})
                })
            payload["tools"] = [{"functionDeclarations": function_declarations}]

        url = f"https://generativelanguage.googleapis.com/v1beta/models/{clean_model}:generateContent?key={api_key}"

        async with httpx.AsyncClient(timeout=120.0) as client:
            response = await client.post(url, json=payload)
            response.raise_for_status()
            data = response.json()

        duration = time.time() - start_time
        print(f"[GOOGLE] ✅ Completed in {duration:.1f}s")

        # Extract content
        candidates = data.get("candidates", [{}])
        content = candidates[0].get("content", {}) if candidates else {}
        parts = content.get("parts", [])

        text_content = ""
        tool_calls = []

        for part in parts:
            if "text" in part:
                text_content += part["text"]
            elif "functionCall" in part:
                fc = part["functionCall"]
                tool_calls.append({
                    "id": f"call_{len(tool_calls)}",
                    "type": "function",
                    "function": {
                        "name": fc.get("name"),
                        "arguments": json.dumps(fc.get("args", {}))
                    }
                })

        return {
            "message": {
                "content": text_content,
                "tool_calls": tool_calls if tool_calls else None,
                "role": "assistant"
            },
            "model": clean_model,
            "provider": "google",
            "usage": data.get("usageMetadata")
        }


class OllamaProvider(BaseProvider):
    """Local Ollama provider"""

    # Phase 80.5: Models that do NOT support tool calling
    # These models will fail with "does not support tools (status code: 400)"
    MODELS_WITHOUT_TOOLS = {
        'deepseek-llm',      # Deepseek 7B lightweight
        'llama2',            # Legacy Llama 2
        'codellama',         # CodeLlama base
        'mistral',           # Mistral 7B base (newer versions support tools)
        'phi',               # Microsoft Phi models
        'gemma',             # Google Gemma base
        'orca-mini',         # Orca lightweight
        'vicuna',            # Vicuna base
    }

    def __init__(self, config: ProviderConfig):
        super().__init__(config)
        self.host = config.base_url or os.getenv('OLLAMA_HOST', 'http://localhost:11434')
        self._available_models: List[str] = []
        self._default_model = 'deepseek-llm:7b'
        self._health_checked = False

    @property
    def supports_tools(self) -> bool:
        return True  # Ollama supports tools

    @property
    def name(self) -> str:
        return "Ollama"

    def _check_health(self):
        """Check Ollama availability and get models"""
        if self._health_checked:
            return

        try:
            import requests
            resp = requests.get(f"{self.host}/api/tags", timeout=5)
            if resp.status_code == 200:
                data = resp.json()
                self._available_models = [m['name'] for m in data.get('models', [])]
                if self._available_models and self._default_model not in self._available_models:
                    self._default_model = self._available_models[0]
                print(f"[OLLAMA] Health check: {len(self._available_models)} models")
        except Exception as e:
            print(f"[OLLAMA] Health check failed: {e}")

        self._health_checked = True

    def _model_supports_tools(self, model_name: str) -> bool:
        """
        Phase 80.5: Check if model supports tool calling.

        Args:
            model_name: Model identifier (e.g., 'deepseek-llm:7b')

        Returns:
            True if model supports tools, False otherwise
        """
        # Extract base model name (remove tag)
        base_name = model_name.split(':')[0].lower()

        # Check against blacklist
        for unsupported in self.MODELS_WITHOUT_TOOLS:
            if unsupported in base_name:
                return False

        return True

    async def call(
        self,
        messages: List[Dict[str, str]],
        model: str,
        tools: Optional[List[Dict]] = None,
        **kwargs
    ) -> Dict[str, Any]:
        import ollama

        start_time = time.time()
        self._check_health()

        # Clean model name
        clean_model = model.replace('ollama/', '')

        # Validate model exists
        if self._available_models and clean_model not in self._available_models:
            print(f"[OLLAMA] Model {clean_model} not found, using {self._default_model}")
            clean_model = self._default_model

        # Phase 80.5: Check if model supports tools
        model_has_tools = self._model_supports_tools(clean_model)
        effective_tools = tools if (tools and model_has_tools) else None

        if tools and not model_has_tools:
            print(f"[OLLAMA] ⚠️  {clean_model} does not support tools - calling without tools")

        print(f"[OLLAMA] Calling {clean_model} (tools: {len(effective_tools) if effective_tools else 0})")

        params = {
            'model': clean_model,
            'messages': messages,
            'stream': False
        }

        if effective_tools:
            params['tools'] = effective_tools

        # Run sync ollama.chat in thread pool
        loop = asyncio.get_event_loop()

        try:
            response = await loop.run_in_executor(
                None,
                lambda: ollama.chat(**params)
            )
        except Exception as e:
            # Phase 80.5: If tools error, retry without tools
            if 'does not support tools' in str(e) and 'tools' in params:
                print(f"[OLLAMA] Tool error detected, retrying {clean_model} without tools")
                del params['tools']
                response = await loop.run_in_executor(
                    None,
                    lambda: ollama.chat(**params)
                )
            else:
                raise

        duration = time.time() - start_time
        print(f"[OLLAMA] ✅ Completed in {duration:.1f}s")

        # Standardize response
        message = response.get('message', {})

        return {
            "message": {
                "content": message.get('content', ''),
                "tool_calls": message.get('tool_calls'),
                "role": message.get('role', 'assistant')
            },
            "model": clean_model,
            "provider": "ollama",
            "usage": None
        }


