// Интеграция WebRTC VAD (npm i webrtcvad)
import VAD from 'webrtcvad';  // Or native via MediaStream

useEffect(() => {
  if (isListening && streamRef.current) {
    const vad = new VAD(2);  // Aggressiveness 0-3
    const audioCtx = new AudioContext();
    const source = audioCtx.createMediaStreamSource(streamRef.current);
    const processor = audioCtx.createScriptProcessor(512, 1, 1);

    processor.onaudioprocess = (e) => {
      const input = e.inputBuffer.getChannelData(0);
      const isSpeech = vad.process(input);  // 10ms frames
      if (!isSpeech) {
        silenceTimer.current += 0.01;  // Accumulate
        if (silenceTimer.current > 1.5) {
          stopListening();  // Auto-stop, send to backend
          silenceTimer.current = 0;
        }
      } else {
        silenceTimer.current = 0;
      }
      setIntensity(isSpeech ? 0.8 : 0.3);  // Update wave
    };
    source.connect(processor);
    processor.connect(audioCtx.destination);
  }
}, [isListening]);
