### 1. Конкретный Код для `write_file_native` в `file_system.rs`
Добавь это в конец `file_system.rs` (Phase 100.2: Direct file read/write without HTTP). Это симметрично `read_file_native`: пишет UTF-8 контент, проверяет размер (<10MB), создаёт dirs если нужно. Для безопасности — только в разрешённые пути (из capabilities, напр. $HOME/**).

```rust
// src-tauri/src/file_system.rs (добавь после list_directory и watch_directory)

use std::fs::{self, File};
use std::io::Write;
use std::path::{Path, PathBuf};

/// Write file content directly (native, no HTTP)
/// Creates parent directories if they don't exist
/// Limits size to prevent abuse
#[tauri::command]
pub async fn write_file_native(path: String, content: String) -> Result<String, String> {
    let file_path = PathBuf::from(&path);

    // Security: Ensure path is within allowed scopes (e.g., $HOME/** from capabilities)
    // In production, validate against tauri::security::Scope or env vars
    if !is_allowed_path(&file_path) {
        return Err("Path not allowed (security restriction)".to_string());
    }

    // Size check
    if content.len() > 10 * 1024 * 1024 {
        return Err("Content too large (>10MB)".to_string());
    }

    // Create parent dirs if needed
    if let Some(parent) = file_path.parent() {
        fs::create_dir_all(parent)
            .map_err(|e| format!("Cannot create directories: {}", e))?;
    }

    // Write file
    let mut file = File::create(&file_path)
        .map_err(|e| format!("Cannot create file: {}", e))?;
    file.write_all(content.as_bytes())
        .map_err(|e| format!("Cannot write file: {}", e))?;
    file.sync_all()
        .map_err(|e| format!("Cannot sync file: {}", e))?;

    Ok(format!("Written successfully: {}", path))
}

/// Helper: Basic path validation (expand for full scope checking)
fn is_allowed_path(path: &PathBuf) -> bool {
    // Example: Allow only under $HOME or specific dirs
    // In Tauri 2.x, use tauri::plugin::fs::Scope for runtime validation
    path.starts_with(std::env::var("HOME").unwrap_or_else(|_| "/tmp".to_string()))
        || path.starts_with("/tmp")
}
