### 3. Обновление `file_system.rs` для Write + Drag & Drop

Твой текущий `file_system.rs` (из pinned) имеет read/list/watch — добавим write-функции и обработку drop. Используй `tauri::command` для IPC, и `notify` для watchers. Вот полный обновлённый модуль (на базе твоего, с новыми fn'ями). Импорты: добавь `use std::fs; use std::io::{self, Write}; use tauri::Manager;`.

```rust
// src-tauri/src/file_system.rs
use std::path::Path;
use tauri::{command, State, AppHandle};
use notify::{Watcher, RecursiveMode, Config, RecommendedWatcher};
use notify_debouncer_mini::new_debouncer;
use std::sync::Arc;
use std::time::Duration;
use serde::{Deserialize, Serialize};
use std::fs;
use std::io::{self, Write as IoWrite};

// State for file watcher (shared across commands)
#[derive(Default)]
pub struct FileWatcherState(Arc<tokio::sync::Mutex<notify::RecommendedWatcher>>);

#[derive(Serialize, Deserialize, Debug, Clone)]
pub struct FileEvent {
    pub path: String,
    pub action: String,  // "create", "write", "remove"
}

// Existing: List files (unchanged)
#[command]
pub async fn list_dir(path: String) -> Result<Vec<String>, String> {
    let path = Path::new(&path);
    if !path.exists() {
        return Err("Path does not exist".to_string());
    }
    let entries = fs::read_dir(path)
        .map_err(|e| e.to_string())?
        .filter_map(|entry| {
            entry.ok().map(|e| e.path().to_string_lossy().into_owned())
        })
        .collect();
    Ok(entries)
}

// Existing: Read file (unchanged)
#[command]
pub async fn read_file(path: String) -> Result<String, String> {
    fs::read_to_string(&path).map_err(|e| e.to_string())
}

// NEW: Write file (for save after drag & drop edit)
#[command]
pub async fn write_file(path: String, content: String) -> Result<(), String> {
    let mut file = fs::OpenOptions::new()
        .write(true)
        .create(true)
        .truncate(true)
        .open(&path)
        .map_err(|e| e.to_string())?;
    file.write_all(content.as_bytes())
        .map_err(|e| e.to_string())?;
    file.sync_all().map_err(|e| e.to_string())?;  // Flush to disk
    Ok(())
}

// NEW: Remove file (for cleanup)
#[command]
pub async fn remove_file(path: String) -> Result<(), String> {
    fs::remove_file(&path).map_err(|e| e.to_string())
}

// Existing: Watch setup (enhanced with debounce for Phase 100.2)
#[command]
pub fn setup_watcher(
    app: AppHandle,
    state: State<'_, FileWatcherState>,
    path: String,
) -> Result<(), String> {
    let path = Path::new(&path).to_owned();
    let (tx, rx) = std::sync::mpsc::channel();
    let mut watcher = RecommendedWatcher::new(tx, Config::default()).map_err(|e| e.to_string())?;

    watcher
        .watch(path.as_ref(), RecursiveMode::Recursive)
        .map_err(|e| e.to_string())?;

    let mut debouncer = new_debouncer(Duration::from_millis(100), None).unwrap();  // Debounce <10ms latency
    debouncer.watcher(&mut watcher).unwrap();

    let app_handle = app.clone();
    let state_inner = state.0.clone();

    // Spawn async task for events
    tauri::async_runtime::spawn(async move {
        let mut mini_debouncer = debouncer;
        for events in rx {
            if let Ok(events) = mini_debouncer.receive(events) {
                for event in events {
                    let file_event = FileEvent {
                        path: event.paths[0].to_string_lossy().to_string(),
                        action: match event.kind {
                            notify::EventKind::Create(_) => "create".to_string(),
                            notify::EventKind::Modify(_) => "write".to_string(),
                            notify::EventKind::Remove(_) => "remove".to_string(),
                            _ => "other".to_string(),
                        },
                    };
                    app_handle.emit_all("file-event", &file_event).unwrap();
                }
            }
        }
    });

    *state_inner.lock().await = Some(watcher);  // Store in state if needed
    Ok(())
}

// NEW: Handle drag & drop (global event listener in main.rs, but expose path handler here)
#[command]
pub async fn handle_drop_paths(paths: Vec<String>) -> Result<Vec<String>, String> {
    // Process dropped files: e.g., read them or emit to UI
    let processed: Vec<String> = paths.iter().map(|p| {
        if let Ok(content) = fs::read_to_string(p) {
            format!("Dropped: {} ({} bytes)", p, content.len())
        } else {
            format!("Dropped: {} (binary/unreadable)", p)
        }
    }).collect();
    Ok(processed)
}
```

