#### Быстрый Код-Скеч для Доработки `heartbeat.rs`
```rust
// src-tauri/src/heartbeat.rs (расширь существующий)
use std::time::Duration;
use tokio::time::interval;
use tauri::{AppHandle, Emitter};
use crate::file_system; // Для локальных checks, если нужно

#[derive(serde::Serialize)]
pub struct HeartbeatPayload {
    pub timestamp: u64,
    pub open_tasks: usize,
    pub message: Option<String>,
    pub should_notify: bool,
}

pub async fn start_heartbeat_loop(handle: AppHandle) {
    let mut ticker = interval(Duration::from_secs(300)); // 5 мин

    loop {
        ticker.tick().await;
        let timestamp = std::time::SystemTime::now()
            .duration_since(std::time::UNIX_EPOCH)
            .unwrap()
            .as_secs();

        // Check open tasks (Qdrant via HTTP или local SQLite stub)
        let open_tasks = match check_open_tasks(&handle).await {
            Ok(tasks) => tasks.len(),
            Err(_) => 0,
        };

        let payload = HeartbeatPayload {
            timestamp,
            open_tasks,
            message: if open_tasks > 0 { Some(format!("{} open tasks — continue?")) } else { None },
            should_notify: open_tasks > 0,
        };

        // Emit to frontend
        if let Err(e) = handle.emit_all("heartbeat", &payload) {
            log::warn!("Heartbeat emit failed: {}", e);
        }

        // Native notification (если should_notify)
        if payload.should_notify {
            tauri_plugin_notification::Notification::new("ai.vetka.app")
                .title("VETKA JARVIS")
                .body(&payload.message.unwrap_or_default())
                .show()
                .ok();
        }

        // Tray badge update (Phase 100.3)
        if let Some(window) = handle.get_webview_window("main") {
            window.tray_handle().set_badge(open_tasks as i32).ok();
        }
    }
}

async fn check_open_tasks(_handle: &AppHandle) -> Result<Vec<String>, Box<dyn std::error::Error>> {
