**Шаг 2: Реализуй STT в `jarvis_handler.py` (15-20 мин, MARKER_104.3)**
- Импорты: `from src.voice.stt_engine import WhisperSTT` (создай если нет: используй mlx-whisper для offline).
- В handler (Socket.IO @sio.event):
  ```python
  # src/api/handlers/jarvis_handler.py
  from collections import deque
  import io
  import wave  # Для буферизации PCM в WAV

  class JarvisHandler:
      def __init__(self, sio):
          self.sio = sio
          self.user_sessions = {}  # {user_id: {'state': 'idle', 'audio_buffer': deque(maxlen=16000*10)}}  # 10s buffer

      @sio.event
      async def jarvis_listen_start(sid, data):
          user_id = data.get('user_id', 'default')
          self.user_sessions[user_id] = {'state': 'listening', 'audio_buffer': deque(maxlen=16000*30)}  # Буфер 30s @16kHz
          await sio.emit('jarvis_state', {'state': 'listening'}, room=sid)

      @sio.event
      async def jarvis_audio_chunk(sid, data):
          user_id = 'default'  # Из сессии или data
          session = self.user_sessions.get(user_id)
          if session and session['state'] == 'listening':
              audio_buffer = data['audio']  # Int16Array buffer → bytes
              session['audio_buffer'].extend(io.BytesIO(audio_buffer).read())  # Append PCM bytes
              # VAD check? (если level > threshold, continue)

      @sio.event
      async def jarvis_listen_stop(sid, data):
          user_id = data.get('user_id', 'default')
          session = self.user_sessions.get(user_id)
          if session:
              # STT: Конверт buffer в WAV, transcribe
              pcm_bytes = b''.join(session['audio_buffer'])
              wav_io = io.BytesIO()
              with wave.open(wav_io, 'wb') as wav_file:
                  wav_file.setnchannels(1)
                  wav_file.setsampwidth(2)  # 16-bit
                  wav_file.setframerate(16000)
                  wav_file.writeframes(pcm_bytes)
              wav_io.seek(0)

              # Whisper STT (mlx-whisper или openai-whisper)
              from mlx_whisper import transcribe  # Или torch
              transcript = await transcribe(wav_io, model='base')  # Async для speed

              await sio.emit('jarvis_transcript', {'text': transcript}, room=sid)
              await sio.emit('jarvis_state', {'state': 'thinking'}, room=sid)

              # LLM: Используй jarvis_agent.py (Hostess + tools)
              from src.agents.jarvis_agent import JarvisAgent
              agent = JarvisAgent()
              response_text = await agent.process(transcript)  # Интегрируй с tree context/search

              await sio.emit('jarvis_response', {'text': response_text}, room=sid)
              await sio.emit('jarvis_state', {'state': 'speaking'}, room=sid)

              # TTS: Streaming chunks
              from src.voice.tts_engine import Qwen3TTSClient
              tts = Qwen3TTSClient(base_url='http://localhost:5002')
              async for chunk_bytes in tts.generate_stream(response_text):  # Async generator
                  await sio.emit('jarvis_audio_chunk', {'audio': b64encode(chunk_bytes).decode(), 'is_last': False}, room=sid)
              await sio.emit('jarvis_audio_chunk', {'is_last': True}, room=sid)  # End
              await sio.emit('jarvis_state', {'state': 'idle'}, room=sid)

              del self.user_sessions[user_id]  # Cleanup

      @sio.event
      async def jarvis_error(sid, data):
          await sio.emit('jarvis_error', {'error': 'STT/TTS failed'}, room=sid)
  ```
